# game.py

from board import Board

def get_move(player):
    while True:
        move = input(f"{player}, enter your move (e.g., a1-a2): ")
        if len(move) != 5 or move[2] != '-':
            print("Invalid move format. Please use from-to notation.")
            continue
        start = move[:2]
        end = move[3:]
        return (start, end)

def convert_position(pos):
    x = ord(pos[0]) - ord('a')
    y = 7 - int(pos[1])
    return (x, y)

def main():
    board = Board()
    current_player = 'B'

    while True:
        board.display()
        start_pos, end_pos = get_move(current_player)
        start = convert_position(start_pos)
        end = convert_position(end_pos)

        if board.is_valid_move(start, end):
            board.make_move(start, end)
            if not board.has_valid_moves('W' if current_player == 'B' else 'B'):
                print(f"{current_player} wins!")
                break
            current_player = 'W' if current_player == 'B' else 'B'
        else:
            print("Invalid move. Try again.")

if __name__ == "__main__":
    main()
```

